using Games.Horse.Application.Services;using Games.Horse.Transport.Grpc.Wire;using Grpc.Net.Client;using Microsoft.AspNetCore.Builder;using Microsoft.AspNetCore.Routing;using Microsoft.Extensions.DependencyInjection;
namespace Games.Horse.Transport.Grpc;public static class HorseGrpcExtensions{public static IServiceCollection AddHorseGrpcClient(this IServiceCollection s,Uri a){s.AddSingleton(_=>GrpcChannel.ForAddress(a));s.AddSingleton(sp=>new HorseApi.HorseApiClient(sp.GetRequiredService<GrpcChannel>()));s.AddScoped<IHorseService,GrpcHorseService>();return s;}public static IEndpointRouteBuilder MapHorseGrpcTransport(this IEndpointRouteBuilder e){e.MapGrpcService<HorseGrpcEndpoint>();return e;}}
